import type { int, long } from "@tsonic/core/types.js";

declare global {
  type JsPrimitive = string | number | boolean | bigint | symbol;
  type JsValue = object | JsPrimitive | null;

  const console: {
    log(...data: JsValue[]): void;
  };

  function parseInt(str: string, radix?: int): long | undefined;
  function setInterval(handler: (...args: JsValue[]) => void, timeout?: int, ...args: JsValue[]): int;
  function clearInterval(id: int): void;
}

export {};
